#include <bits/stdc++.h>
using namespace std;vector<int>p;
int f(int x){return p[x]==x?x:p[x]=f(p[x]);}
int main(){int n,m;cin>>n>>m;p.resize(n+1);for(int i=1;i<=n;i++)p[i]=i;for(int i=1;i<=n;i++)for(int j=1;j<=n;j++){int x;cin>>x;if(x)p[f(i)]=f(j);}vector<int>plan(m);for(auto&x:plan)cin>>x;bool ok=true;for(int i=1;i<m;i++)if(f(plan[i])!=f(plan[0])){ok=false;break;}cout<<(ok?"YES":"NO")<<"\n";}
